    "content": "# Python Standard Library Topics You Should Know\n\n## itertools\n\nUseful for memory-efficient iteration.\n\n```python\nfrom itertools import count, cycle, repeat, chain, islice, groupby, product, combinations, permutations\n\nprint(list(islice(count(10), 5)))        # [10, 11, 12, 13, 14]\nprint(list(chain([1, 2], [3, 4])))       # [1, 2, 3, 4]\nprint(list(product([\"S\", \"M\"], [\"red\", \"blue\"])))\n```\n\n### groupby requires sorted/grouped input\n\n```python\nfrom itertools import groupby\n\nitems = sorted([\n    {\"city\": \"Delhi\", \"name\": \"A\"},\n    {\"city\": \"Mumbai\", \"name\": \"B\"},\n    {\"city\": \"Delhi\", \"name\": \"C\"},\n], key=lambda x: x[\"city\"])\n\nfor city, group in groupby(items, key=lambda x: x[\"city\"]):\n    print(city, list(group))\n```\n\n## functools\n\n```python\nfrom functools import lru_cache, partial, reduce, wraps, singledispatch\n\n@lru_cache(maxsize=128)\ndef fib(n):\n    if n < 2:\n        return n\n    return fib(n - 1) + fib(n - 2)\n\nprint(fib(35))\n```\n\n### partial\n\n```python\nfrom functools import partial\n\ndef power(base, exponent):\n    return base ** exponent\n\nsquare = partial(power, exponent=2)\nprint(square(5))\n```\n\n### singledispatch\n\n```python\nfrom functools import singledispatch\n\n@singledispatch\ndef serialize(value):\n    return str(value)\n\n@serialize.register\ndef _(value: dict):\n    return value.items()\n```\n\n## contextlib\n\n```python\nfrom contextlib import contextmanager\n\n@contextmanager\ndef transaction():\n    print(\"BEGIN\")\n    try:\n        yield\n        print(\"COMMIT\")\n    except Exception:\n        print(\"ROLLBACK\")\n        raise\n\nwith transaction():\n    print(\"insert row\")\n```\n\n## pathlib\n\n```python\nfrom pathlib import Path\n\nroot = Path(\"logs\")\nfor path in root.glob(\"*.log\"):\n    print(path.name, path.read_text())\n```\n\nUse `pathlib` instead of manual string path handling.\n\n## datetime\n\n```python\nfrom datetime import datetime, timezone, timedelta\n\nnow = datetime.now(timezone.utc)\nexpires_at = now + timedelta(minutes=15)\nprint(expires_at.isoformat())\n```\n\nAlways be careful with timezone-aware vs timezone-naive datetimes.\n\n## json\n\n```python\nimport json\n\ndata = {\"name\": \"A\", \"active\": True}\ntext = json.dumps(data)\nback = json.loads(text)\n```\n\n## logging\n\n```python\nimport logging\n\nlogging.basicConfig(level=logging.INFO)\nlogger = logging.getLogger(__name__)\n\nlogger.info(\"User created\", extra={\"user_id\": 123})\n```\n\nIn production, prefer structured logs with correlation IDs.\n\n## typing\n\n```python\nfrom typing import Optional, Union, Literal, TypedDict, Protocol, TypeVar, Generic\n\nclass UserDict(TypedDict):\n    id: int\n    email: str\n\nclass SupportsSave(Protocol):\n    def save(self) -> None: ...\n```\n\nTypes do not run at runtime by default; they help editors, linters, and maintainers.",
    "searchText": "python python standard library topics you should know python standard library topics you should know itertools useful for memory-efficient iteration. groupby requires sorted/grouped input functools partial singledispatch contextlib pathlib use pathlib instead of manual string path handling. datetime always be car... # python standard library topics you should know ## itertools useful for memory-efficient iteration. ```python from itertools import count, cycle, repeat, chain, islice, groupby, product, combinations, permutations print(list(islice(count(10), 5))) # [10, 11, 12, 13, 14] print(list(chain([1, 2], [3, 4]))) # [1, 2, 3, 4] print(list(product([\"s\", \"m\"], [\"red\", \"blue\"]))) ``` ### groupby requires sorted/grouped input ```python from itertools import groupby items = sorted([ {\"city\": \"delhi\", \"name\": \"a\"}, {\"city\": \"mumbai\", \"name\": \"b\"}, {\"city\": \"delhi\", \"name\": \"c\"}, ], key=lambda x: x[\"city\"]) for city, group in groupby(items, key=lambda x: x[\"city\"]): print(city, list(group)) ``` ## functools ```python from functools import lru_cache, partial, reduce, wraps, singledispatch @lru_cache(maxsize=128) def fib(n): if n < 2: return n return fib(n - 1) + fib(n - 2) print(fib(35)) ``` ### partial ```python from functools import partial def power(base, exponent): return base ** exponent square = partial(power, exponent=2) print(square(5)) ``` ### singledispatch ```python from functools import singledispatch @singledispatch def serialize(value): return str(value) @serialize.register def _(value: dict): return value.items() ``` ## contextlib ```python from contextlib import contextmanager @contextmanager def transaction(): print(\"begin\") try: yield print(\"commit\") except exception: print(\"rollback\") raise with transaction(): print(\"insert row\") ``` ## pathlib ```python from pathlib import path root = path(\"logs\") for path in root.glob(\"*.log\"): print(path.name, path.read_text()) ``` use `pathlib` instead of manual string path handling. ## datetime ```python from datetime import datetime, timezone, timedelta now = datetime.now(timezone.utc) expires_at = now + timedelta(minutes=15) print(expires_at.isoformat()) ``` always be careful with timezone-aware vs timezone-naive datetimes. ## json ```python import json data = {\"name\": \"a\", \"active\": true} text = json.dumps(data) back = json.loads(text) ``` ## logging ```python import logging logging.basicconfig(level=logging.info) logger = logging.getlogger(__name__) logger.info(\"user created\", extra={\"user_id\": 123}) ``` in production, prefer structured logs with correlation ids. ## typing ```python from typing import optional, union, literal, typeddict, protocol, typevar, generic class userdict(typeddict): id: int email: str class supportssave(protocol): def save(self) -> none: ... ``` types do not run at runtime by default; they help editors, linters, and maintainers."
